package main
import ("context";"encoding/json";"net/http";"github.com/go-chi/chi/v5";"github.com/jackc/pgx/v5/pgxpool")
func main(){db,_:=pgxpool.New(context.Background(),"postgres://postgres:postgres@postgres:5432/hypercompute?sslmode=disable");r:=chi.NewRouter();r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("model_up 1"))});r.Get("/models",func(w http.ResponseWriter,r *http.Request){rows,_:=db.Query(r.Context(),"select model_name,status from models");defer rows.Close();a:=[]map[string]any{};for rows.Next(){var n,s string;rows.Scan(&n,&s);a=append(a,map[string]any{"model":n,"status":s})};json.NewEncoder(w).Encode(map[string]any{"data":a})});r.Get("/price",func(w http.ResponseWriter,r *http.Request){m:=r.URL.Query().Get("model");var p float64;_ = db.QueryRow(r.Context(),"select unit_price from model_pricing where model_name=$1",m).Scan(&p);json.NewEncoder(w).Encode(map[string]any{"unit_price":p})});http.ListenAndServe(":8088",r)}
